#ifndef CALCULATOR_H
#define CALCULATOR_H

#include <stdint.h>

/* Return codes */
#define CALC_OK        (0)
#define CALC_ERR_DIV0  (-1)

int32_t calc_add(int32_t a, int32_t b);
int32_t calc_subtract(int32_t a, int32_t b);
int32_t calc_multiply(int32_t a, int32_t b);
int32_t calc_divide(int32_t a, int32_t b, int32_t *result);

#endif /* CALCULATOR_H */

/**
 * @file    calculator.c
 * @brief   Basic arithmetic operations module
 * @version 1.0
 */

#include "include/calculator.h"

int32_t calc_add(int32_t a, int32_t b)
{
    return a + b;
}

int32_t calc_subtract(int32_t a, int32_t b)
{
    return a - b;
}

int32_t calc_multiply(int32_t a, int32_t b)
{
    return a * b;
}

int32_t calc_divide(int32_t a, int32_t b, int32_t *result)
{
    if (b == 0)
    {
        return CALC_ERR_DIV0;
    }
    *result = a / b;
    return CALC_OK;
}
